mapper.select:
SELECT (
    SELECT COUNT(*)
    FROM consignment_external_supplier external_supplier
    WHERE external_supplier.item_code = #{itemCode}
      AND external_supplier.supplier_code = #{supplierCode}
      AND external_supplier.supplier_contract = #{supplierContract}
      AND external_supplier.consignee_store = #{store}
) + (
    SELECT COUNT(*)
    FROM consignment_internal_supplier internal_supplier
    WHERE internal_supplier.item_code = #{itemCode}
      AND internal_supplier.supplier_code = #{supplierCode}
      AND internal_supplier.supplier_store = #{internalSupplierStore}
      AND internal_supplier.consignee_store = #{store}
)
